solution_code:
#include <iostream>

int main()
{
    int total_cents{};
    std::cin >> total_cents;

    int quarters{ total_cents / 25 };
    int remaining_cents{ total_cents % 25 };

    int dimes{ remaining_cents / 10 };
    remaining_cents = remaining_cents % 10;

    int nickels{ remaining_cents / 5 };
    int pennies{ remaining_cents % 5 };

    std::cout << "Quarters: " << quarters << '\n';
    std::cout << "Dimes: " << dimes << '\n';
    std::cout << "Nickels: " << nickels << '\n';
    std::cout << "Pennies: " << pennies << '\n';

    return 0;
}
